import configparser as cp
import requests


def fetch_dependencies():
    c = cp.ConfigParser()

    try:
        resp = requests.get(url='https://raw.githubusercontent.com/theskumba/coding-test/master/requirements.txt',
                            stream=True)

        if resp.status_code != 200:
            raise RuntimeError('Error fetching dependencies, received {} status'.format(resp))

        c.readfp(resp.raw)

    except requests.RequestException as e:
        print("Requests raised an error: {}".format(e))
    return [l for l in [x for x in c['requirements']][0].split()]


if __name__ == '__main__':
    print(fetch_dependencies())